void solve(int CASE)
{
	int n; cin >> n;
	var mp = vector<vector<pii>>(n + 1);
	fa(i, 1, n) {
		int a, b; cin >> a >> b;
		mp[a].pb({ b, i });
	}
	fa(i, 1, n)sort(all(mp[i]), greater<>());
	var ans = vector<int>();
	fb(i, n, 1)if (mp[i].size()) {
		int mx = ans.size(), cnt = 0;
		for (const var& [b, id] : mp[i]) {
			cnt++;
			mx = max(min((int)ans.size(), b) + cnt, mx);
		}
		if (mx > ans.size()) {
			var now = vector<int>();
			for (const var& [b, id] : mp[i]) {
				now.pb(id);
				if (min((int)ans.size(), b) + now.size() == mx) {
					int j = 0;
					fa(i, min((int)ans.size(), b), vs(ans)) {
						ans[i] = now[j];
						j++;
					}
					while (j <= vs(now))ans.pb(now[j++]);
					break;
				}
			}
		}
	}
	cout << ans.size() << endl;
	cout << ans << endl;
	return;
}
